        foreach ($group in $groups) {
            # Sort descending so index 0 = newest
            [PSCustomObject[]]$sorted = @($group.Group | Sort-Object -Property CreatedAt -Descending)

            if ($sorted.Count -gt $keepCount) {
                for ([int]$i = $keepCount; $i -lt $sorted.Count; $i++) {
